  1	import type { FC, FormEvent, ReactNode } from 'react';
  2	import { FormGroupWithHelpText } from 'src/components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  3	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
  4	
  5	import { ProviderModelGroupVersionKind, type V1beta1Provider } from '@kubev2v/types';
  6	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
  7	import { Form, FormSelect, FormSelectOption } from '@patternfly/react-core';
  8	
  9	type FindProviderFunction = (args: {
 10	  providers: V1beta1Provider[];
 11	  name: string;
 12	}) => V1beta1Provider | undefined;
 13	
 14	const findProvider: FindProviderFunction = ({ name, providers }) =>
 15	  providers.find((provider) => provider.metadata?.name === name);
 16	
 17	const ProviderOption = (provider: V1beta1Provider, index: number) => (
 18	  <FormSelectOption
 19	    key={provider?.metadata?.name ?? index}
 20	    value={provider?.metadata?.name}
 21	    label={provider?.metadata?.name ?? ''}
 22	  />
 23	);
 24	
 25	export const ProvidersEdit: FC<ProvidersEditProps> = ({
 26	  helpContent,
 27	  invalidLabel,
 28	  label,
 29	  mode,
 30	  onChange,
 31	  placeHolderLabel,
 32	  providers,
 33	  selectedProviderName,
 34	  setMode,
 35	}) => {
 36	  const targetProvider = findProvider({ name: selectedProviderName, providers });
 37	
 38	  const validated = targetProvider ? 'success' : 'error';
 39	  const hasProviders = providers?.length > 0;
 40	
 41	  if (mode === 'edit') {
 42	    return (
 43	      <Form isWidthLimited>
 44	        <FormGroupWithHelpText
 45	          label={label}
 46	          isRequired
 47	          fieldId="targetProvider"
 48	          validated={validated}
 49	          helperTextInvalid={invalidLabel}
 50	        >
 51	          <FormSelect
 52	            value={selectedProviderName}
 53	            onChange={(e, value) => {
 54	              onChange(value, e);
 55	            }}
 56	            id="targetProvider"
 57	            isDisabled={!hasProviders}
 58	            validated={validated}
 59	          >
 60	            {[
 61	              <FormSelectOption
 62	                key="placeholder"
 63	                value={''}
 64	                label={placeHolderLabel}
 65	                isPlaceholder
 66	                isDisabled
 67	              />,
 68	              ...providers.map(ProviderOption),
 69	            ]}
 70	          </FormSelect>
 71	        </FormGroupWithHelpText>
 72	      </Form>
 73	    );
 74	  }
 75	  return (
 76	    <DetailsItem
 77	      title={label}
 78	      content={
 79	        <ResourceLink
 80	          inline
 81	          name={selectedProviderName}
 82	          namespace={targetProvider?.metadata?.namespace}
 83	          groupVersionKind={ProviderModelGroupVersionKind}
 84	          linkTo={Boolean(targetProvider)}
 85	        />
 86	      }
 87	      onEdit={
 88	        hasProviders
 89	          ? () => {
 90	              setMode('edit');
 91	            }
 92	          : undefined
 93	      }
 94	      helpContent={helpContent}
 95	      crumbs={['spec', 'providers']}
 96	    />
 97	  );
 98	};
 99	
100	type ProvidersEditProps = {
101	  providers: V1beta1Provider[];
102	  selectedProviderName: string;
103	  onChange: (value: string, event: FormEvent<HTMLSelectElement>) => void;
104	  label: string;
105	  placeHolderLabel: string;
106	  invalidLabel: string;
107	  helpContent: ReactNode;
108	  mode: 'edit' | 'view';
109	  setMode: (mode: 'edit' | 'view') => void;
110	};

